% SECTION 2: RULES (predefined — do NOT modify)
% ============================================================

%--- Component-level pass/fail -----------------------------------
% A component is failed if it has passing_marks > 0 and obtained < passing_marks
component_failed(RollNo, SubId, Semester, CompName) :-
    marks(RollNo, SubId, Semester, CompName, _, PassMin, Obtained, _),
    PassMin > 0,
    Obtained < PassMin.

%--- Subject total marks (sum of all components) -----------------
subject_total(RollNo, SubId, Semester, Total) :-
    findall(Obt,
        marks(RollNo, SubId, Semester, _, _, _, Obt, _),
        ObtList),
    ObtList \= [],
    sumlist(ObtList, Total).

%--- Subject max marks (sum of all component max marks) ----------
subject_max(RollNo, SubId, Semester, MaxTotal) :-
    findall(Max,
        marks(RollNo, SubId, Semester, _, Max, _, _, _),
        MaxList),
    MaxList \= [],
    sumlist(MaxList, MaxTotal).

%--- Subject percentage (normalized to 100 scale) ----------------
subject_percentage(RollNo, SubId, Semester, Pct) :-
    subject_total(RollNo, SubId, Semester, Total),
    subject_max(RollNo, SubId, Semester, MaxTotal),
    MaxTotal > 0,
    Pct is (Total / MaxTotal) * 100.

%--- Subject pass/fail -------------------------------------------
passes_subject(RollNo, SubId, Semester) :-
    marks(RollNo, SubId, Semester, _, _, _, _, _),
    \+ component_failed(RollNo, SubId, Semester, _).

fails_subject(RollNo, SubId, Semester) :-
    component_failed(RollNo, SubId, Semester, _).

%--- Grade points (10-point scale based on percentage) -----------
grade_points(Pct, 10) :- Pct >= 91, !.
grade_points(Pct,  9) :- Pct >= 81, !.
grade_points(Pct,  8) :- Pct >= 71, !.
grade_points(Pct,  7) :- Pct >= 61, !.
grade_points(Pct,  6) :- Pct >= 55, !.
grade_points(Pct,  5) :- Pct >= 50, !.
grade_points(Pct,  4) :- Pct >= 40, !.
grade_points(_,     0).

%--- Number of backlogs (failed subjects) -------------------------
number_of_backlogs(RollNo, Semester, Count) :-
    findall(SubId,
        ( marks(RollNo, SubId, Semester, _, _, _, _, _),
          fails_subject(RollNo, SubId, Semester) ),
        RawList),
    sort(RawList, UniqueList),
    length(UniqueList, Count).

%--- Total credits earned (sum of credits_earned from marks) ------
% Credits earned are stored per-component but should be same for all
% components of a subject. We take the max per subject to avoid double-counting.
total_credits(RollNo, Semester, TotalCredits) :-
    findall(SubId-Cr,
        marks(RollNo, SubId, Semester, _, _, _, _, Cr),
        Pairs),
    collect_max_credits(Pairs, [], CrPairs),
    extract_credits(CrPairs, CrList),
    sumlist(CrList, TotalCredits).

% Helper: collect max credit per unique subject
collect_max_credits([], Acc, Acc).
collect_max_credits([SubId-Cr | Rest], Acc, Result) :-
    ( member(SubId-ExCr, Acc) ->
        ( Cr > ExCr ->
            delete(Acc, SubId-ExCr, Acc1),
            collect_max_credits(Rest, [SubId-Cr | Acc1], Result)
        ;
            collect_max_credits(Rest, Acc, Result)
        )
    ;
        collect_max_credits(Rest, [SubId-Cr | Acc], Result)
    ).

% Extract credit values from SubId-Cr pairs
extract_credits([], []).
extract_credits([_-Cr | Rest], [Cr | CrRest]) :-
    extract_credits(Rest, CrRest).

%--- Unique subjects in a semester --------------------------------
semester_subjects(RollNo, Semester, Subjects) :-
    findall(SubId,
        marks(RollNo, SubId, Semester, _, _, _, _, _),
        RawList),
    sort(RawList, Subjects).

%--- SGPA calculation (component-based) ---------------------------
sgpa(RollNo, Semester, SGPA) :-
    semester_subjects(RollNo, Semester, Subjects),
    Subjects \= [],
    compute_wgp(RollNo, Semester, Subjects, 0, 0, TotalWGP, TotalCr),
    TotalCr > 0,
    SGPA is TotalWGP / TotalCr.

compute_wgp(_, _, [], WAcc, CAcc, WAcc, CAcc).
compute_wgp(RollNo, Semester, [SubId | Rest], WAcc, CAcc, WSum, CrSum) :-
    subject(SubId, _, Cr),
    subject_percentage(RollNo, SubId, Semester, Pct),
    grade_points(Pct, GP),
    WAcc1 is WAcc + GP * Cr,
    CAcc1 is CAcc + Cr,
    compute_wgp(RollNo, Semester, Rest, WAcc1, CAcc1, WSum, CrSum).

%--- Grace marks calculation (component-based) --------------------
% Grace only if exactly 1 subject failed AND total marks needed <= 6
grace_used(RollNo, Semester, Grace) :-
    number_of_backlogs(RollNo, Semester, Count),
    ( Count =:= 1 ->
        findall(CompName-(PassMin - Obtained),
            ( marks(RollNo, _, Semester, CompName, _, PassMin, Obtained, _),
              PassMin > 0,
              Obtained < PassMin ),
            FailedComps),
        sum_grace_needed(FailedComps, 0, TotalNeeded),
        ( TotalNeeded =< 6 -> Grace = TotalNeeded ; Grace = 0 )
    ;
        Grace = 0
    ).

sum_grace_needed([], Acc, Acc).
sum_grace_needed([_-(PassMin - Obtained) | Rest], Acc, Total) :-
    Needed is PassMin - Obtained,
    Acc1 is Acc + Needed,
    sum_grace_needed(Rest, Acc1, Total).

%--- Result status ------------------------------------------------
result_status(RollNo, Semester, Status) :-
    number_of_backlogs(RollNo, Semester, Count),
    grace_used(RollNo, Semester, Grace),
    ( Count =:= 0 ->
        Status = 'PASS'
    ; Count =:= 1, Grace > 0 ->
        Status = 'PASS (Grace)'
    ; Count =:= 1 ->
        Status = 'ATKT'
    ;
        Status = 'FAIL'
    ).

%--- Total credits for ALL subjects in a semester -----------------
total_credits_all(RollNo, Semester, TotalCr) :-
    semester_subjects(RollNo, Semester, Subjects),
    sum_subject_credits(Subjects, 0, TotalCr).

sum_subject_credits([], Acc, Acc).
sum_subject_credits([SubId | Rest], Acc, Total) :-
    subject(SubId, _, Cr),
    Acc1 is Acc + Cr,
    sum_subject_credits(Rest, Acc1, Total).

%--- Weighted sum helper for CGPA ---------------------------------
sum_weighted([], WSum, CrSum, WSum, CrSum).
sum_weighted([SGPA * Cr | Rest], WAcc, CAcc, WSum, CrSum) :-
    WAcc1 is WAcc + SGPA * Cr,
    CAcc1 is CAcc + Cr,
    sum_weighted(Rest, WAcc1, CAcc1, WSum, CrSum).

%--- CGPA (cumulative across all semesters) -----------------------
cgpa(RollNo, CGPA) :-
    findall(Sem, marks(RollNo, _, Sem, _, _, _, _, _), RawSems),
    sort(RawSems, Semesters),
    Semesters \= [],
    findall(SGPA_Val * TotalCr,
        ( member(S, Semesters),
          sgpa(RollNo, S, SGPA_Val),
          total_credits_all(RollNo, S, TotalCr),
          TotalCr > 0 ),
        Pairs),
    Pairs \= [],
    sum_weighted(Pairs, 0, 0, WSum, CrSum),
    CrSum > 0,
    CGPA is WSum / CrSum.

%--- Next year eligibility ----------------------------------------
next_year_eligible(RollNo, TotalBacklogs, TotalCreditsEarned, MinCredits, Eligible) :-
    student(RollNo, _, _, _, Year, _),
    OddSem is Year * 2 - 1,
    EvenSem is Year * 2,
    MinCredits = 34,
    findall(SubId-S,
        ( member(S, [OddSem, EvenSem]),
          marks(RollNo, SubId, S, _, _, _, _, _),
          fails_subject(RollNo, SubId, S) ),
        RawFailedPairs),
    sort(RawFailedPairs, FailedPairs),
    length(FailedPairs, TotalBacklogs),
    findall(SubId-S-Cr,
        ( member(S, [OddSem, EvenSem]),
          marks(RollNo, SubId, S, _, _, _, _, Cr) ),
        RawCrPairs),
    sort(RawCrPairs, UniqueCrPairs),
    sum_cr_pairs(UniqueCrPairs, [], [], FinalCrs),
    sumlist(FinalCrs, TotalCreditsEarned),
    ( TotalBacklogs =< 3, TotalCreditsEarned >= MinCredits ->
        Eligible = 'YES'
    ;
        Eligible = 'NO'
    ).

% Helper to get unique credits per subject-semester
% Tracks seen SubId-S pairs and accumulates numeric Cr values
sum_cr_pairs([], _, Acc, Acc).
sum_cr_pairs([SubId-S-Cr | Rest], Seen, Acc, Result) :-
    ( member(SubId-S, Seen) ->
        sum_cr_pairs(Rest, Seen, Acc, Result)
    ;
        sum_cr_pairs(Rest, [SubId-S | Seen], [Cr | Acc], Result)
    ).
